### SWR Library

SWR is a React Hooks library for data fetching created by Vercel. The name comes from **stale-while-revalidate**. It handles caching, revalidation, refetching, and error handling.

### Installation

```bash
npm install swr
```

### Basic Usage with useSWR

```jsx
import useSWR from 'swr';

const fetcher = (url) => fetch(url).then((res) => res.json());

export default function Profile() {
  const { data, error, isLoading } = useSWR('/api/user', fetcher);

  if (error) return <div>Failed to load</div>;
  if (isLoading) return <div>Loading...</div>;

  return <div>Hello {data.name}!</div>;
}
```

### Fetcher Function

The fetcher receives the key (URL) and returns a Promise. You can customize it:

```jsx
const fetcher = async (url) => {
  const res = await fetch(url);
  if (!res.ok) {
    const error = new Error('An error occurred');
    error.info = await res.json();
    error.status = res.status;
    throw error;
  }
  return res.json();
};
```

### Revalidation with Mutate

Manually refetch or update cache:

```jsx
import useSWR, { mutate } from 'swr';

export default function Posts() {
  const { data } = useSWR('/api/posts', fetcher);

  const createPost = async (newPost) => {
    await fetch('/api/posts', { method: 'POST', body: JSON.stringify(newPost) });
    mutate('/api/posts'); // revalidate
  };

  // Optimistic update
  const addOptimistic = (newPost) => {
    mutate('/api/posts', [...data, newPost], false); // false = no revalidation
  };

  return <div>...</div>;
}
```

### Pagination

```jsx
import useSWR from 'swr';

function PaginatedPosts() {
  const [page, setPage] = useState(1);
  const { data } = useSWR(`/api/posts?page=${page}`, fetcher);

  return (
    <div>
      {data?.posts.map(post => <Post key={post.id} post={post} />)}
      <button onClick={() => setPage(p => p - 1)}>Previous</button>
      <button onClick={() => setPage(p => p + 1)}>Next</button>
    </div>
  );
}
```

### Global Configuration

Wrap your app with `SWRConfig`:

```jsx
import { SWRConfig } from 'swr';

export default function App({ Component, pageProps }) {
  return (
    <SWRConfig value={{ refreshInterval: 3000, fetcher }}>
      <Component {...pageProps} />
    </SWRConfig>
  );
}
```

codeExample:
import useSWR from 'swr';

const fetcher = (url) => fetch(url).then(r => r.json());

export default function Dashboard() {
  const { data: user, error: userError } = useSWR('/api/user', fetcher);
  const { data: stats, error: statsError } = useSWR('/api/stats', fetcher, {
    refreshInterval: 10000,
  });

  if (userError || statsError) return <div>Error loading data</div>;
  if (!user || !stats) return <div>Loading...</div>;

  return (
    <div>
      <h1>Welcome {user.name}</h1>
      <p>Active users: {stats.activeUsers}</p>
    </div>
  );
}
